502	njs_int_t
503	ngx_js_ext_fetch(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
504	    njs_index_t unused, njs_value_t *retval)
505	{
506	    njs_int_t            ret;
507	    ngx_url_t            u;
508	    ngx_str_t           *resolve_host;
509	    ngx_pool_t          *pool;
510	    njs_value_t         *init, *value;
511	    ngx_js_http_t       *http;
512	    ngx_js_fetch_t      *fetch;
513	    ngx_js_request_t     request;
514	    ngx_connection_t    *c;
515	    ngx_resolver_ctx_t  *ctx;
516	    njs_external_ptr_t   external;
517	    njs_opaque_value_t   lvalue;
518	
519	    static const njs_str_t buffer_size_key = njs_str("buffer_size");
520	    static const njs_str_t body_size_key = njs_str("max_response_body_size");
521	#if (NGX_SSL)
522	    static const njs_str_t verify_key = njs_str("verify");
523	#endif
524	
525	    external = njs_vm_external_ptr(vm);
526	    c = ngx_external_connection(vm, external);
527	    pool = ngx_external_pool(vm, external);
528	
529	    fetch = ngx_js_fetch_alloc(vm, pool, c->log,
530	                               ngx_external_loc_conf(vm, external));
531	    if (fetch == NULL) {
532	        return NJS_ERROR;
533	    }
534	
535	    http = &fetch->http;
536	
537	    ret = ngx_js_request_constructor(vm, &request, &u, external, args, nargs);
538	    if (ret != NJS_OK) {
539	        goto fail;
540	    }
541	
542	    if (u.host.len >= NGX_JS_HOST_MAX_LEN) {
543	        njs_vm_type_error(vm, "Host name too long");
544	        goto fail;
545	    }
546	
547	    http->host = u.host;
548	    http->port = u.port;
549	    http->response.url = request.url;
550	    http->buffer_size = http->conf->buffer_size;
551	    http->max_response_body_size = http->conf->max_response_body_size;
552	
553	#if (NGX_SSL)
554	    if (ngx_js_https(&u)) {
555	        http->ssl = http->conf->ssl;
556	        http->ssl_verify = http->conf->ssl_verify;
557	    }
558	#endif
559	
560	    init = njs_arg(args, nargs, 2);
561	
562	    if (njs_value_is_object(init)) {
563	        value = njs_vm_object_prop(vm, init, &buffer_size_key, &lvalue);
564	        if (value != NULL
565	            && ngx_js_integer(vm, value, &http->buffer_size)
566	               != NGX_OK)
567	        {
568	            goto fail;
569	        }
570	
571	        value = njs_vm_object_prop(vm, init, &body_size_key, &lvalue);
572	        if (value != NULL
573	            && ngx_js_integer(vm, value, &http->max_response_body_size)
574	               != NGX_OK)
575	        {
576	            goto fail;
577	        }
578	
579	#if (NGX_SSL)
580	        value = njs_vm_object_prop(vm, init, &verify_key, &lvalue);
581	        if (value != NULL) {
582	            http->ssl_verify = njs_value_bool(value);
583	        }
584	#endif
585	    }
586	
587	#if (NGX_SSL)
588	    if (http->ssl != NULL && !http->ssl_verify) {
589	        http->keepalive = 0;
590	    }
591	#endif
592	
593	    if (request.method.len == 4
594	        && ngx_strncasecmp(request.method.data, (u_char *) "HEAD", 4) == 0)
595	    {
596	        http->header_only = 1;
597	    }
598	
599	    NJS_CHB_MP_INIT(&http->chain, njs_vm_memory_pool(vm));
600	    NJS_CHB_MP_INIT(&http->response.chain, njs_vm_memory_pool(vm));
601	
602	    resolve_host = NULL;
603	    http->connect_port = http->port;
604	
605	    if (ngx_js_conf_proxy(http->conf)) {
606	        if (ngx_js_conf_dynamic_proxy(http->conf)) {
607	            if (http->conf->eval_proxy_url(http->pool, external, http->conf,
608	                                           &http->proxy.url, &http->proxy.auth)
609	                != NGX_OK)
610	            {
611	                njs_vm_internal_error(vm, "failed to evaluate proxy URL");
612	                goto fail;
613	            }
614	
615	        } else {
616	            http->proxy.url = http->conf->fetch_proxy_url;
617	            http->proxy.auth = http->conf->fetch_proxy_auth_header;
618	        }
619	
620	        if (ngx_js_http_proxy(http) && http->proxy.url->addrs == NULL) {
621	            resolve_host = &http->proxy.url->host;
622	            http->connect_port = http->proxy.url->port;
623	        }
624	    }
625	
626	    if (!ngx_js_http_proxy(http) && u.addrs == NULL) {
627	        resolve_host = &u.host;
628	    }
629	
630	    if (ngx_js_check_request_line_component(u.uri.data, u.uri.len) != NGX_OK) {
631	        njs_vm_type_error(vm, "invalid url");
632	        goto fail;
633	    }
634	
635	    ngx_js_fetch_build_request(http, &request, &u.uri, &u,
636	                               ngx_js_http_proxy(http) && !ngx_js_https(&u));
637	
638	    if (resolve_host != NULL) {
639	        ngx_log_debug0(NGX_LOG_DEBUG_EVENT, http->log, 0,
640	                       "js http fetch: resolving");
641	
642	        ctx = ngx_js_http_resolve(http, ngx_external_resolver(vm, external),
643	                                  resolve_host,
644	                                  ngx_external_resolver_timeout(vm, external));
645	
646	        if (ctx == NULL) {
647	            njs_vm_memory_error(vm);
648	            goto fail;
649	        }
650	
651	        if (ctx == NGX_NO_RESOLVER) {
652	            njs_vm_internal_error(vm, "no resolver defined");
653	            goto fail;
654	        }
655	
656	        njs_value_assign(retval, njs_value_arg(&fetch->promise));
657	
658	        return NJS_OK;
659	    }
660	
661	    http->naddrs = 1;
662	    http->addrs = &http->addr;
663	
664	    if (ngx_js_http_proxy(http)) {
665	        ngx_memcpy(&http->addr, &http->proxy.url->addrs[0], sizeof(ngx_addr_t));
666	
667	    } else {
668	        ngx_memcpy(&http->addr, &u.addrs[0], sizeof(ngx_addr_t));
669	    }
670	
671	    ngx_js_http_connect(http);
672	
673	    njs_value_assign(retval, njs_value_arg(&fetch->promise));
674	
675	    return NJS_OK;
676	
677	fail:
678	
679	    ngx_log_debug2(NGX_LOG_DEBUG_EVENT, http->log, 0,
680	                   "js http done fetch:%p rc:%d", fetch, NJS_ERROR);
681	
682	    ngx_js_del_event(ngx_external_ctx(vm,  njs_vm_external_ptr(vm)),
683	                     fetch->event);
684	
685	    return ngx_js_fetch_promissified_result(vm, NULL, NJS_ERROR, retval);
686	}
