805	            }
806	
807	            if (response->code < 200 || response->code > 599) {
808	                njs_vm_range_error(vm, "status provided (%i) is outside of "
809	                                   "[200, 599] range", response->code);
810	                return NJS_ERROR;
811	            }
812	        }
813	
814	        value = njs_vm_object_prop(vm, init, &status_text, &lvalue);
815	        if (value != NULL) {
816	            if (ngx_js_ngx_string(vm, value, &response->status_text) != NGX_OK) {
817	                return NJS_ERROR;
818	            }
819	
820	            p = response->status_text.data;
821	            end = p + response->status_text.len;
822	
823	            while (p < end) {
824	                if (*p != '\t' && *p < ' ') {
825	                    njs_vm_type_error(vm, "invalid Response statusText");
826	                    return NJS_ERROR;
827	                }
828	
829	                p++;
830	            }
831	        }
832	
833	        value = njs_vm_object_prop(vm, init, &headers, &lvalue);
834	        if (value != NULL) {
835	            if (!njs_value_is_object(value)) {
836	                njs_vm_type_error(vm, "Headers is not an object");
837	                return NJS_ERROR;
838	            }
839	
840	            ret = ngx_js_headers_fill(vm, &response->headers, value);
841	            if (ret != NJS_OK) {
842	                return NJS_ERROR;
843	            }
844	        }
845	    }
846	
847	    NJS_CHB_MP_INIT(&response->chain, njs_vm_memory_pool(vm));
848	
849	    body = njs_arg(args, nargs, 1);
850	
851	    if (!njs_value_is_null_or_undefined(body)) {
852	        if (ngx_js_string(vm, body, &bd) != NGX_OK) {
853	            return NJS_ERROR;
854	        }
855	
856	        njs_chb_append(&response->chain, bd.start, bd.length);
857	
858	        if (njs_value_is_string(body)) {
859	            ret = ngx_js_headers_append(vm, &response->headers,
860	                                    (u_char *) "Content-Type",
861	                                    njs_length("Content-Type"),
862	                                    (u_char *) "text/plain;charset=UTF-8",
863	                                    njs_length("text/plain;charset=UTF-8"));
864	            if (ret != NJS_OK) {
865	                return NJS_ERROR;
866	            }
867	        }
868	    }
869	
870	    return njs_vm_external_create(vm, retval,
871	                                  ngx_http_js_fetch_response_proto_id, response,
872	                                  0);
873	}
