876	static njs_int_t
877	ngx_js_method_process(njs_vm_t *vm, ngx_js_request_t *request)
878	{
879	    u_char           *s, *p;
880	    njs_str_t        str;
881	    const njs_str_t  *m;
882	
883	    static const njs_str_t forbidden[] = {
884	        njs_str("CONNECT"),
885	        njs_str("TRACE"),
886	        njs_str("TRACK"),
887	        njs_null_str,
888	    };
889	
890	    static const njs_str_t to_normalize[] = {
891	        njs_str("DELETE"),
892	        njs_str("GET"),
893	        njs_str("HEAD"),
894	        njs_str("OPTIONS"),
895	        njs_str("POST"),
896	        njs_str("PUT"),
897	        njs_null_str,
898	    };
899	
900	    str.start = request->method.data;
901	    str.length = request->method.len;
902	
903	    if (request->method.len == 0
904	        || ngx_js_check_request_line_component(request->method.data,
905	                                               request->method.len)
906	           != NGX_OK)
907	    {
908	        njs_vm_type_error(vm, "invalid Request method");
909	        return NJS_ERROR;
910	    }
911	
912	    for (m = &forbidden[0]; m->length != 0; m++) {
913	        if (njs_strstr_case_eq(&str, m)) {
914	            njs_vm_type_error(vm, "forbidden method: %V", m);
915	            return NJS_ERROR;
916	        }
917	    }
918	
919	    for (m = &to_normalize[0]; m->length != 0; m++) {
920	        if (njs_strstr_case_eq(&str, m)) {
921	            s = &request->m[0];
922	            p = m->start;
923	
924	            while (*p != '\0') {
925	                *s++ = njs_upper_case(*p++);
926	            }
927	
928	            request->method.data = &request->m[0];
929	            request->method.len = m->length;
930	            break;
931	        }
932	    }
933	
934	    return NJS_OK;
935	}
