938	static njs_int_t
939	ngx_js_headers_inherit(njs_vm_t *vm, ngx_js_headers_t *headers,
940	    ngx_js_headers_t *orig)
941	{
942	    njs_int_t         ret;
943	    ngx_uint_t        i;
944	    ngx_list_part_t  *part;
945	    ngx_js_tb_elt_t  *h;
946	
947	    part = &orig->header_list.part;
948	    h = part->elts;
949	
950	    for (i = 0; /* void */; i++) {
951	
952	        if (i >= part->nelts) {
953	            if (part->next == NULL) {
954	                break;
955	            }
956	
957	            part = part->next;
958	            h = part->elts;
959	            i = 0;
960	        }
961	
962	        if (h[i].hash == 0) {
963	            continue;
964	        }
965	
966	        ret = ngx_js_headers_append(vm, headers, h[i].key.data, h[i].key.len,
967	                                    h[i].value.data, h[i].value.len);
968	        if (ret != NJS_OK) {
969	            return NJS_ERROR;
970	        }
971	    }
972	
973	    return NJS_OK;
974	}
