976	static njs_int_t
977	ngx_js_headers_fill(njs_vm_t *vm, ngx_js_headers_t *headers, njs_value_t *init)
978	{
979	    int64_t              i, len, length;
980	    njs_int_t            ret;
981	    njs_str_t            name, header;
982	    njs_value_t         *keys, *value;
983	    ngx_js_headers_t    *hh;
984	    njs_opaque_value_t  *e, *start, lvalue;
985	
986	    hh = njs_vm_external(vm, ngx_http_js_fetch_headers_proto_id, init);
987	
988	    if (hh != NULL) {
989	        return ngx_js_headers_inherit(vm, headers, hh);
990	    }
991	
992	    if (njs_value_is_array(init)) {
993	        start = (njs_opaque_value_t *) njs_vm_array_start(vm, init);
994	        if (start == NULL) {
995	            return NJS_ERROR;
996	        }
997	
998	        (void) njs_vm_array_length(vm, init, &length);
999	
1000	        for (i = 0; i < length; i++) {
1001	            e = (njs_opaque_value_t *) njs_vm_array_start(vm,
1002	                                                          njs_value_arg(start));
1003	            if (e == NULL) {
1004	                return NJS_ERROR;
1005	            }
1006	
1007	            (void) njs_vm_array_length(vm, njs_value_arg(start), &len);
1008	
1009	            start++;
1010	
1011	            if (len != 2) {
1012	                njs_vm_type_error(vm,
1013	                                  "header does not contain exactly two items");
1014	                return NJS_ERROR;
1015	            }
1016	
1017	            if (ngx_js_string(vm, njs_value_arg(&e[0]), &name) != NGX_OK) {
1018	                return NJS_ERROR;
1019	            }
1020	
1021	            if (ngx_js_string(vm, njs_value_arg(&e[1]), &header) != NGX_OK) {
1022	                return NJS_ERROR;
1023	            }
1024	
1025	            ret = ngx_js_headers_append(vm, headers, name.start, name.length,
1026	                                        header.start, header.length);
1027	            if (ret != NJS_OK) {
1028	                return NJS_ERROR;
1029	            }
1030	        }
1031	
1032	    } else {
1033	        keys = njs_vm_object_keys(vm, init, njs_value_arg(&lvalue));
1034	        if (keys == NULL) {
1035	            return NJS_ERROR;
1036	        }
1037	
1038	        start = (njs_opaque_value_t *) njs_vm_array_start(vm, keys);
1039	        if (start == NULL) {
1040	            return NJS_ERROR;
1041	        }
1042	
1043	        (void) njs_vm_array_length(vm, keys, &length);
1044	
1045	        for (i = 0; i < length; i++) {
1046	            if (ngx_js_string(vm, njs_value_arg(start), &name) != NGX_OK) {
1047	                return NJS_ERROR;
1048	            }
1049	
1050	            start++;
1051	
1052	            value = njs_vm_object_prop(vm, init, &name, &lvalue);
1053	            if (value == NULL) {
1054	                return NJS_ERROR;
1055	            }
1056	
1057	            if (ngx_js_string(vm, value, &header) != NGX_OK) {
1058	                return NJS_ERROR;
1059	            }
1060	
1061	            ret = ngx_js_headers_append(vm, headers, name.start, name.length,
1062	                                        header.start, header.length);
1063	            if (ret != NJS_OK) {
1064	                return NJS_ERROR;
1065	            }
1066	        }
1067	    }
1068	
1069	    return NJS_OK;
1070	}
