1073	static ngx_js_fetch_t *
1074	ngx_js_fetch_alloc(njs_vm_t *vm, ngx_pool_t *pool, ngx_log_t *log,
1075	    ngx_js_loc_conf_t *conf)
1076	{
1077	    njs_int_t        ret;
1078	    ngx_js_ctx_t    *ctx;
1079	    ngx_js_http_t   *http;
1080	    ngx_js_fetch_t  *fetch;
1081	    ngx_js_event_t  *event;
1082	    njs_function_t  *callback;
1083	
1084	    fetch = ngx_pcalloc(pool, sizeof(ngx_js_fetch_t));
1085	    if (fetch == NULL) {
1086	        goto failed;
1087	    }
1088	
1089	    /*
1090	     * set by ngx_pcalloc():
1091	     *
1092	     * fetch->http.proxy.state = HTTP_STATE_DIRECT;
1093	     */
1094	
1095	    http = &fetch->http;
1096	
1097	    http->pool = pool;
1098	    http->log = log;
1099	    http->conf = conf;
1100	
1101	    http->content_length_n = -1;
1102	    http->keepalive = (conf->fetch_keepalive > 0
1103	                       && !ngx_js_conf_dynamic_proxy(conf));
1104	
1105	    http->append_headers = ngx_js_fetch_append_headers;
1106	    http->ready_handler = ngx_js_fetch_process_done;
1107	    http->error_handler = ngx_js_fetch_error;
1108	
1109	    ret = njs_vm_promise_create(vm, njs_value_arg(&fetch->promise),
1110	                                njs_value_arg(&fetch->promise_callbacks));
1111	    if (ret != NJS_OK) {
1112	        goto failed;
1113	    }
1114	
1115	    callback = njs_vm_function_alloc(vm, ngx_js_http_promise_trampoline, 0, 0);
1116	    if (callback == NULL) {
1117	        goto failed;
1118	    }
1119	
1120	    event = njs_mp_zalloc(njs_vm_memory_pool(vm), sizeof(ngx_js_event_t));
1121	    if (njs_slow_path(event == NULL)) {
1122	        goto failed;
1123	    }
1124	
1125	    ctx = ngx_external_ctx(vm, njs_vm_external_ptr(vm));
1126	
1127	    event->ctx = vm;
1128	    njs_value_function_set(njs_value_arg(&event->function), callback);
1129	    event->destructor = ngx_js_fetch_destructor;
1130	    event->fd = ctx->event_id++;
1131	    event->data = fetch;
1132	
1133	    ngx_js_add_event(ctx, event);
1134	
1135	    fetch->vm = vm;
1136	    fetch->event = event;
1137	
1138	    ngx_log_debug1(NGX_LOG_DEBUG_EVENT, log, 0, "js http alloc:%p", fetch);
1139	
1140	    return fetch;
1141	
1142	failed:
1143	
1144	    njs_vm_internal_error(vm, "internal error");
1145	
1146	    return NULL;
1147	}
