1182	static njs_int_t
1183	ngx_js_fetch_promissified_result(njs_vm_t *vm, njs_value_t *result,
1184	    njs_int_t rc, njs_value_t *retval)
1185	{
1186	    njs_int_t            ret;
1187	    njs_function_t      *callback;
1188	    njs_opaque_value_t   promise, arguments[2];
1189	
1190	    ret = njs_vm_promise_create(vm, njs_value_arg(&promise),
1191	                                njs_value_arg(&arguments));
1192	    if (ret != NJS_OK) {
1193	        goto error;
1194	    }
1195	
1196	    callback = njs_vm_function_alloc(vm, ngx_js_http_promise_trampoline, 0, 0);
1197	    if (callback == NULL) {
1198	        goto error;
1199	    }
1200	
1201	    njs_value_assign(&arguments[0], &arguments[(rc != NJS_OK)]);
1202	
1203	    if (rc != NJS_OK) {
1204	        njs_vm_exception_get(vm, njs_value_arg(&arguments[1]));
1205	
1206	    } else {
1207	        njs_value_assign(&arguments[1], result);
1208	    }
1209	
1210	    ret = njs_vm_enqueue_job(vm, callback, njs_value_arg(&arguments), 2);
1211	    if (ret == NJS_ERROR) {
1212	        goto error;
1213	    }
1214	
1215	    njs_value_assign(retval, &promise);
1216	
1217	    return NJS_OK;
1218	
1219	error:
1220	
1221	    njs_vm_internal_error(vm, "internal error");
1222	
1223	    return NJS_ERROR;
1224	}
