1227	static void
1228	ngx_js_fetch_done(ngx_js_fetch_t *fetch, njs_opaque_value_t *retval,
1229	    njs_int_t rc)
1230	{
1231	    njs_vm_t            *vm;
1232	    ngx_js_ctx_t        *ctx;
1233	    ngx_js_http_t       *http;
1234	    ngx_js_event_t      *event;
1235	    njs_opaque_value_t   arguments[2], *action;
1236	
1237	    http = &fetch->http;
1238	
1239	    ngx_log_debug2(NGX_LOG_DEBUG_EVENT, http->log, 0,
1240	                   "js http done fetch:%p rc:%i", fetch, (ngx_int_t) rc);
1241	
1242	    ngx_js_http_close_peer(http);
1243	
1244	    if (fetch->event != NULL) {
1245	        action = &fetch->promise_callbacks[(rc != NJS_OK)];
1246	        njs_value_assign(&arguments[0], action);
1247	        njs_value_assign(&arguments[1], retval);
1248	
1249	        vm = fetch->vm;
1250	        event = fetch->event;
1251	
1252	        rc = ngx_js_call(vm, njs_value_function(njs_value_arg(&event->function)),
1253	                         &arguments[0], 2);
1254	
1255	        ctx = ngx_external_ctx(vm,  njs_vm_external_ptr(vm));
1256	        ngx_js_del_event(ctx, event);
1257	
1258	        ngx_external_event_finalize(vm)(njs_vm_external_ptr(vm), rc);
1259	    }
1260	}
