1264	ngx_js_http_promise_trampoline(njs_vm_t *vm, njs_value_t *args,
1265	    njs_uint_t nargs, njs_index_t unused, njs_value_t *retval)
1266	{
1267	    njs_function_t  *callback;
1268	
1269	    callback = njs_value_function(njs_argument(args, 1));
1270	
1271	    if (callback != NULL) {
1272	        return njs_vm_call(vm, callback, njs_argument(args, 2), 1);
1273	    }
1274	
1275	    return NJS_OK;
1276	}
