1279	static njs_int_t
1280	ngx_js_request_constructor(njs_vm_t *vm, ngx_js_request_t *request,
1281	    ngx_url_t *u, njs_external_ptr_t external, njs_value_t *args,
1282	    njs_uint_t nargs)
1283	{
1284	    njs_int_t            ret;
1285	    ngx_uint_t           rc;
1286	    ngx_pool_t          *pool;
1287	    njs_value_t         *input, *init, *value, *headers;
1288	    ngx_js_request_t    *orig;
1289	    njs_opaque_value_t   lvalue;
1290	
1291	    static const njs_str_t body_key = njs_str("body");
1292	    static const njs_str_t cache_key = njs_str("cache");
1293	    static const njs_str_t cred_key = njs_str("credentials");
1294	    static const njs_str_t headers_key = njs_str("headers");
1295	    static const njs_str_t mode_key = njs_str("mode");
1296	    static const njs_str_t method_key = njs_str("method");
1297	
1298	    input = njs_arg(args, nargs, 1);
1299	    if (njs_value_is_undefined(input)) {
1300	        njs_vm_type_error(vm, "1st argument is required");
1301	        return NJS_ERROR;
1302	    }
1303	
1304	    /*
1305	     * set by ngx_memzero():
1306	     *
1307	     *  request->url.length = 0;
1308	     *  request->body.length = 0;
1309	     *  request->cache_mode = CACHE_MODE_DEFAULT;
1310	     *  request->credentials = CREDENTIALS_SAME_ORIGIN;
1311	     *  request->mode = MODE_NO_CORS;
1312	     *  request->headers.content_type = NULL;
1313	     */
1314	
1315	    ngx_memzero(request, sizeof(ngx_js_request_t));
1316	
1317	    request->method.data = (u_char *) "GET";
1318	    request->method.len = 3;
1319	    request->body.data = (u_char *) "";
1320	    request->body.len = 0;
1321	    request->headers.guard = GUARD_REQUEST;
1322	
1323	    pool = ngx_external_pool(vm, external);
1324	
1325	    rc = ngx_list_init(&request->headers.header_list, pool, 4,
1326	                       sizeof(ngx_js_tb_elt_t));
1327	    if (rc != NGX_OK) {
1328	        njs_vm_memory_error(vm);
1329	        return NJS_ERROR;
1330	    }
1331	
1332	    if (njs_value_is_string(input)) {
1333	        ret = ngx_js_ngx_string(vm, input, &request->url);
1334	        if (ret != NJS_OK) {
1335	            return NJS_ERROR;
1336	        }
1337	
1338	    } else {
1339	        orig = njs_vm_external(vm, ngx_http_js_fetch_request_proto_id, input);
1340	        if (orig == NULL) {
1341	            njs_vm_type_error(vm, "input is not string or a Request object");
1342	            return NJS_ERROR;
1343	        }
1344	
1345	        request->url = orig->url;
1346	        request->method = orig->method;
1347	        request->body = orig->body;
1348	        request->body_used = orig->body_used;
1349	        request->cache_mode = orig->cache_mode;
1350	        request->credentials = orig->credentials;
1351	        request->mode = orig->mode;
1352	
1353	        ret = ngx_js_headers_inherit(vm, &request->headers, &orig->headers);
1354	        if (ret != NJS_OK) {
1355	            return NJS_ERROR;
1356	        }
1357	    }
1358	
1359	    ngx_js_http_trim(&request->url.data, &request->url.len, 1);
1360	
1361	    ngx_memzero(u, sizeof(ngx_url_t));
1362	
1363	    u->url.len = request->url.len;
1364	    u->url.data = request->url.data;
1365	    u->default_port = NGX_JS_HTTP_DEFAULT_PORT;
1366	    u->uri_part = 1;
1367	    u->no_resolve = 1;
1368	
1369	    if (u->url.len > 7
1370	        && njs_strncasecmp(u->url.data, (u_char *) "http://", 7) == 0)
1371	    {
1372	        u->url.len -= 7;
1373	        u->url.data += 7;
1374	
1375	#if (NGX_SSL)
1376	    } else if (u->url.len > 8
1377	        && njs_strncasecmp(u->url.data, (u_char *) "https://", 8) == 0)
1378	    {
1379	        u->url.len -= 8;
1380	        u->url.data += 8;
1381	        u->default_port = NGX_JS_HTTPS_DEFAULT_PORT;
1382	#endif
1383	
1384	    } else {
1385	        njs_vm_type_error(vm, "unsupported URL schema (only http or https are"
1386	                          " supported)");
1387	        return NJS_ERROR;
1388	    }
1389	
1390	    if (ngx_parse_url(pool, u) != NGX_OK) {
1391	        njs_vm_type_error(vm, "invalid url");
1392	        return NJS_ERROR;
1393	    }
1394	
1395	    init = njs_arg(args, nargs, 2);
1396	
1397	    if (njs_value_is_object(init)) {
1398	        value = njs_vm_object_prop(vm, init, &method_key, &lvalue);
1399	        if (value != NULL && ngx_js_ngx_string(vm, value, &request->method)
1400	            != NGX_OK)
1401	        {
1402	            return NJS_ERROR;
1403	        }
1404	
1405	        ret = ngx_js_method_process(vm, request);
1406	        if (ret != NJS_OK) {
1407	            return NJS_ERROR;
1408	        }
1409	
1410	        value = njs_vm_object_prop(vm, init, &cache_key, &lvalue);
1411	        if (value != NULL) {
1412	            ret = ngx_fetch_flag_set(vm, ngx_js_fetch_cache_modes, value,
1413	                                     "cache");
1414	            if (ret == NJS_ERROR) {
1415	                return NJS_ERROR;
1416	            }
1417	
1418	            request->cache_mode = ret;
1419	        }
1420	
1421	        value = njs_vm_object_prop(vm, init, &cred_key, &lvalue);
1422	        if (value != NULL) {
1423	            ret = ngx_fetch_flag_set(vm, ngx_js_fetch_credentials, value,
1424	                                     "credentials");
1425	            if (ret == NJS_ERROR) {
1426	                return NJS_ERROR;
1427	            }
1428	
1429	            request->credentials = ret;
1430	        }
1431	
1432	        value = njs_vm_object_prop(vm, init, &mode_key, &lvalue);
1433	        if (value != NULL) {
1434	            ret = ngx_fetch_flag_set(vm, ngx_js_fetch_modes, value, "mode");
1435	            if (ret == NJS_ERROR) {
1436	                return NJS_ERROR;
1437	            }
1438	
1439	            request->mode = ret;
1440	        }
1441	
1442	        headers = njs_vm_object_prop(vm, init, &headers_key, &lvalue);
1443	        if (headers != NULL) {
1444	            if (!njs_value_is_object(headers)) {
1445	                njs_vm_type_error(vm, "Headers is not an object");
1446	                return NJS_ERROR;
1447	            }
1448	
1449	            /*
1450	             * There are no API to reset or destroy ngx_list,
1451	             * just allocating a new one.
1452	             */
1453	
1454	            ngx_memset(&request->headers, 0, sizeof(ngx_js_headers_t));
1455	            request->headers.guard = GUARD_REQUEST;
1456	
1457	            rc = ngx_list_init(&request->headers.header_list, pool, 4,
1458	                               sizeof(ngx_js_tb_elt_t));
1459	            if (rc != NGX_OK) {
1460	                njs_vm_memory_error(vm);
1461	                return NJS_ERROR;
1462	            }
1463	
1464	            ret = ngx_js_headers_fill(vm, &request->headers, headers);
1465	            if (ret != NJS_OK) {
1466	                return NJS_ERROR;
1467	            }
1468	        }
1469	
1470	        value = njs_vm_object_prop(vm, init, &body_key, &lvalue);
1471	        if (value != NULL) {
1472	            if (ngx_js_ngx_string(vm, value, &request->body) != NGX_OK) {
1473	                return NJS_ERROR;
1474	            }
1475	
1476	            if (request->headers.content_type == NULL
1477	                && njs_value_is_string(value))
1478	            {
1479	                ret = ngx_js_headers_append(vm, &request->headers,
1480	                                        (u_char *) "Content-Type",
1481	                                        njs_length("Content-Type"),
1482	                                        (u_char *) "text/plain;charset=UTF-8",
1483	                                        njs_length("text/plain;charset=UTF-8"));
1484	                if (ret != NJS_OK) {
1485	                    return NJS_ERROR;
1486	                }
1487	            }
1488	        }
1489	    }
1490	
1491	    return NJS_OK;
1492	}
