1528	static njs_int_t
1529	ngx_js_headers_append(njs_vm_t *vm, ngx_js_headers_t *headers,
1530	    u_char *name, size_t len, u_char *value, size_t vlen)
1531	{
1532	    ngx_int_t         ret;
1533	    ngx_uint_t        i;
1534	    ngx_js_tb_elt_t  *h, **ph;
1535	    ngx_list_part_t  *part;
1536	
1537	    ngx_js_http_trim_ows(&value, &vlen);
1538	
1539	    ret = ngx_js_check_header_name(name, len);
1540	    if (ret != NGX_OK) {
1541	        njs_vm_type_error(vm, "invalid header name");
1542	        return NJS_ERROR;
1543	    }
1544	
1545	    ret = ngx_js_check_header_value(value, vlen);
1546	    if (ret != NGX_OK) {
1547	        njs_vm_type_error(vm, "invalid header value");
1548	        return NJS_ERROR;
1549	    }
1550	
1551	    if (headers->guard == GUARD_IMMUTABLE) {
1552	        njs_vm_type_error(vm, "cannot append to immutable object");
1553	        return NJS_ERROR;
1554	    }
1555	
1556	    ph = NULL;
1557	    part = &headers->header_list.part;
1558	    h = part->elts;
1559	
1560	    for (i = 0; /* void */; i++) {
1561	
1562	        if (i >= part->nelts) {
1563	            if (part->next == NULL) {
1564	                break;
1565	            }
1566	
1567	            part = part->next;
1568	            h = part->elts;
1569	            i = 0;
1570	        }
1571	
1572	        if (h[i].hash == 0) {
1573	            continue;
1574	        }
1575	
1576	        if (len == h[i].key.len
1577	            && (njs_strncasecmp(name, h[i].key.data, len) == 0))
1578	        {
1579	            ph = &h[i].next;
1580	            while (*ph) { ph = &(*ph)->next; }
1581	            break;
1582	        }
1583	    }
1584	
1585	    h = ngx_list_push(&headers->header_list);
1586	    if (h == NULL) {
1587	        njs_vm_memory_error(vm);
1588	        return NJS_ERROR;
1589	    }
1590	
1591	    if (ph != NULL) {
1592	        *ph = h;
1593	    }
1594	
1595	    h->hash = 1;
1596	    h->key.data = name;
1597	    h->key.len = len;
1598	    h->value.data = value;
1599	    h->value.len = vlen;
1600	    h->next = NULL;
1601	
1602	    if (len == njs_strlen("Content-Type")
1603	        && ngx_strncasecmp(name, (u_char *) "Content-Type", len) == 0)
1604	    {
1605	        headers->content_type = h;
1606	    }
1607	
1608	    return NJS_OK;
1609	}
