1612	static njs_int_t
1613	ngx_headers_js_get(njs_vm_t *vm, njs_value_t *value, njs_str_t *name,
1614	    njs_value_t *retval, njs_bool_t as_array)
1615	{
1616	    njs_int_t          rc;
1617	    njs_chb_t          chain;
1618	    ngx_uint_t         i;
1619	    ngx_js_tb_elt_t   *h, *ph;
1620	    ngx_list_part_t   *part;
1621	    ngx_js_headers_t  *headers;
1622	
1623	    headers = njs_vm_external(vm, ngx_http_js_fetch_headers_proto_id, value);
1624	    if (headers == NULL) {
1625	        njs_value_null_set(retval);
1626	        return NJS_DECLINED;
1627	    }
1628	
1629	    if (as_array) {
1630	        rc = njs_vm_array_alloc(vm, retval, 2);
1631	        if (rc != NJS_OK) {
1632	            return NJS_ERROR;
1633	        }
1634	    }
1635	
1636	    part = &headers->header_list.part;
1637	    h = part->elts;
1638	    ph = NULL;
1639	
1640	    for (i = 0; /* void */; i++) {
1641	
1642	        if (i >= part->nelts) {
1643	            if (part->next == NULL) {
1644	                break;
1645	            }
1646	
1647	            part = part->next;
1648	            h = part->elts;
1649	            i = 0;
1650	        }
1651	
1652	        if (h[i].hash == 0) {
1653	            continue;
1654	        }
1655	
1656	        if (h[i].key.len == name->length
1657	            && njs_strncasecmp(h[i].key.data, name->start, name->length) == 0)
1658	        {
1659	            ph = &h[i];
1660	            break;
1661	        }
1662	    }
1663	
1664	    if (as_array) {
1665	        while (ph != NULL) {
1666	            value = njs_vm_array_push(vm, retval);
1667	            if (value == NULL) {
1668	                return NJS_ERROR;
1669	            }
1670	
1671	            rc = njs_vm_value_string_create(vm, value, ph->value.data,
1672	                                            ph->value.len);
1673	            if (rc != NJS_OK) {
1674	                return NJS_ERROR;
1675	            }
1676	
1677	            ph = ph->next;
1678	        }
1679	
1680	        return NJS_OK;
1681	    }
1682	
1683	    if (ph == NULL) {
1684	        njs_value_null_set(retval);
1685	        return NJS_DECLINED;
1686	    }
1687	
1688	    NJS_CHB_MP_INIT(&chain, njs_vm_memory_pool(vm));
1689	
1690	    h = ph;
1691	
1692	    for ( ;; ) {
1693	        njs_chb_append(&chain, h->value.data, h->value.len);
1694	
1695	        if (h->next == NULL) {
1696	            break;
1697	        }
1698	
1699	        njs_chb_append_literal(&chain, ", ");
1700	        h = h->next;
1701	    }
1702	
1703	    rc = njs_vm_value_string_create_chb(vm, retval, &chain);
1704	
1705	    njs_chb_destroy(&chain);
1706	
1707	    return rc;
1708	}
