1810	static njs_int_t
1811	ngx_headers_js_ext_for_each(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
1812	    njs_index_t unused, njs_value_t *retval)
1813	{
1814	    int64_t              length;
1815	    njs_int_t            ret;
1816	    njs_str_t            name;
1817	    njs_value_t         *this, *callback;
1818	    ngx_js_headers_t    *headers;
1819	    njs_opaque_value_t  *k, *end, keys, arguments[2];
1820	
1821	    this = njs_argument(args, 0);
1822	
1823	    headers = njs_vm_external(vm, ngx_http_js_fetch_headers_proto_id, this);
1824	    if (headers == NULL) {
1825	        njs_vm_type_error(vm, "\"this\" is not fetch headers object");
1826	        return NJS_ERROR;
1827	    }
1828	
1829	    callback = njs_arg(args, nargs, 1);
1830	
1831	    if (!njs_value_is_function(callback)) {
1832	        njs_vm_type_error(vm, "\"callback\" is not a function");
1833	        return NJS_ERROR;
1834	    }
1835	
1836	    ret = ngx_headers_js_ext_keys(vm, this, njs_value_arg(&keys));
1837	    if (ret != NJS_OK) {
1838	        return NJS_ERROR;
1839	    }
1840	
1841	    (void) njs_vm_array_length(vm, njs_value_arg(&keys), &length);
1842	
1843	    k = (njs_opaque_value_t *) njs_vm_array_start(vm, njs_value_arg(&keys));
1844	    end = k + length;
1845	
1846	    for (; k < end; k++) {
1847	        ret = ngx_js_string(vm, njs_value_arg(k), &name);
1848	        if (ret != NJS_OK) {
1849	            return NJS_ERROR;
1850	        }
1851	
1852	        ret = ngx_headers_js_get(vm, this, &name, njs_value_arg(&arguments[1]),
1853	                                 0);
1854	        if (ret != NJS_OK) {
1855	            return NJS_ERROR;
1856	        }
1857	
1858	        njs_value_assign(&arguments[0], k);
1859	
1860	        ret = njs_vm_call(vm, njs_value_function(callback),
1861	                          njs_value_arg(&arguments[0]), 2);
1862	        if (ret != NJS_OK) {
1863	            return NJS_ERROR;
1864	        }
1865	    }
1866	
1867	    return NJS_OK;
1868	}
