1937	static void
1938	ngx_js_sort(void *base, size_t n, size_t size,
1939	    ngx_int_t (*cmp)(const void *, const void *, void *), void *ctx)
1940	{
1941	    u_char  *p1, *p2, *p;
1942	
1943	    p = ngx_alloc(size, ngx_cycle->log);
1944	    if (p == NULL) {
1945	        return;
1946	    }
1947	
1948	    for (p1 = (u_char *) base + size;
1949	         p1 < (u_char *) base + n * size;
1950	         p1 += size)
1951	    {
1952	        ngx_memcpy(p, p1, size);
1953	
1954	        for (p2 = p1;
1955	             p2 > (u_char *) base && cmp(p2 - size, p, ctx) > 0;
1956	             p2 -= size)
1957	        {
1958	            ngx_memcpy(p2, p2 - size, size);
1959	        }
1960	
1961	        ngx_memcpy(p2, p, size);
1962	    }
1963	
1964	    ngx_free(p);
1965	}
