1972	    njs_str_t          hdr;
1973	    ngx_uint_t         i, k, length;
1974	    njs_value_t       *start;
1975	    ngx_list_part_t   *part;
1976	    ngx_js_tb_elt_t   *h;
1977	    ngx_js_headers_t  *headers;
1978	
1979	    headers = njs_vm_external(vm, ngx_http_js_fetch_headers_proto_id, value);
1980	    if (headers == NULL) {
1981	        njs_value_null_set(keys);
1982	        return NJS_DECLINED;
1983	    }
1984	
1985	    rc = njs_vm_array_alloc(vm, keys, 8);
1986	    if (rc != NJS_OK) {
1987	        return NJS_ERROR;
1988	    }
1989	
1990	    length = 0;
1991	
1992	    part = &headers->header_list.part;
1993	    h = part->elts;
1994	
1995	    for (i = 0; /* void */; i++) {
1996	
1997	        if (i >= part->nelts) {
1998	            if (part->next == NULL) {
1999	                break;
2000	            }
2001	
2002	            part = part->next;
2003	            h = part->elts;
2004	            i = 0;
2005	        }
2006	
2007	        if (h[i].hash == 0) {
2008	            continue;
2009	        }
2010	
2011	        start = njs_vm_array_start(vm, keys);
2012	
2013	        for (k = 0; k < length; k++) {
2014	            njs_value_string_get(vm, njs_argument(start, k), &hdr);
2015	
2016	            if (h[i].key.len == hdr.length
2017	                && njs_strncasecmp(h[i].key.data, hdr.start, hdr.length) == 0)
2018	            {
2019	                break;
2020	            }
2021	        }
2022	
2023	        if (k == length) {
2024	            value = njs_vm_array_push(vm, keys);
2025	            if (value == NULL) {
