2049	ngx_headers_js_ext_set(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
2050	    njs_index_t unused, njs_value_t *retval)
2051	{
2052	    njs_int_t          ret;
2053	    njs_str_t          name, value;
2054	    ngx_uint_t         i;
2055	    ngx_list_part_t   *part;
2056	    ngx_js_tb_elt_t   *h, **ph, **pp;
2057	    ngx_js_headers_t  *headers;
2058	
2059	    headers = njs_vm_external(vm, ngx_http_js_fetch_headers_proto_id,
2060	                              njs_argument(args, 0));
2061	    if (headers == NULL) {
2062	        njs_vm_type_error(vm, "\"this\" is not fetch headers object");
2063	        return NJS_ERROR;
2064	    }
2065	
2066	    ret = ngx_js_string(vm, njs_arg(args, nargs, 1), &name);
2067	    if (ret != NJS_OK) {
2068	        return NJS_ERROR;
2069	    }
2070	
2071	    ret = ngx_js_string(vm, njs_arg(args, nargs, 2), &value);
2072	    if (ret != NJS_OK) {
2073	        return NJS_ERROR;
2074	    }
2075	
2076	    part = &headers->header_list.part;
2077	    h = part->elts;
2078	
2079	    for (i = 0; /* void */; i++) {
2080	
2081	        if (i >= part->nelts) {
2082	            if (part->next == NULL) {
2083	                break;
2084	            }
2085	
2086	            part = part->next;
2087	            h = part->elts;
2088	            i = 0;
2089	        }
2090	
2091	        if (h[i].hash == 0) {
2092	            continue;
2093	        }
2094	
2095	        if (name.length == h[i].key.len
2096	            && (njs_strncasecmp(name.start, h[i].key.data, name.length) == 0))
2097	        {
2098	            h[i].value.len = value.length;
2099	            h[i].value.data = value.start;
2100	
2101	            ph = &h[i].next;
2102	
2103	            while (*ph) {
2104	                pp = ph;
2105	                ph = &(*ph)->next;
2106	                *pp = NULL;
2107	            }
2108	
2109	            goto done;
2110	        }
2111	    }
2112	
2113	    ret = ngx_js_headers_append(vm, headers, name.start, name.length,
2114	                                value.start, value.length);
2115	    if (ret != NJS_OK) {
2116	        return NJS_ERROR;
2117	    }
2118	
2119	done:
2120	
2121	    njs_value_undefined_set(retval);
2122	
2123	    return NJS_OK;
2124	}
