#include "ngx_js.h"
#include "ngx_js_http.h"


typedef struct {
    njs_str_t       name;
    njs_int_t       value;
} ngx_js_entry_t;


typedef struct {
    ngx_js_http_t                  http;

    njs_vm_t                      *vm;
    ngx_js_event_t                *event;

    njs_opaque_value_t             response_value;

    njs_opaque_value_t             promise;
    njs_opaque_value_t             promise_callbacks[2];
} ngx_js_fetch_t;


