84	ngx_js_http_resolve(ngx_js_http_t *http, ngx_resolver_t *r, ngx_str_t *host,
85	    ngx_msec_t timeout)
86	{
87	    ngx_int_t            ret;
88	    ngx_resolver_ctx_t  *ctx;
89	
90	    ctx = ngx_resolve_start(r, NULL);
91	    if (ctx == NULL) {
92	        return NULL;
93	    }
94	
95	    if (ctx == NGX_NO_RESOLVER) {
96	        return ctx;
97	    }
98	
99	    http->ctx = ctx;
100	
101	    ctx->name = *host;
102	    ctx->handler = ngx_js_http_resolve_handler;
103	    ctx->data = http;
104	    ctx->timeout = timeout;
105	
106	    ret = ngx_resolve_name(ctx);
107	    if (ret != NGX_OK) {
108	        http->ctx = NULL;
109	        return NULL;
110	    }
111	
112	    return ctx;
