116	static void
117	ngx_js_http_resolve_handler(ngx_resolver_ctx_t *ctx)
118	{
119	    u_char           *p;
120	    size_t            len;
121	    socklen_t         socklen;
122	    ngx_uint_t        i;
123	    ngx_js_http_t    *http;
124	    struct sockaddr  *sockaddr;
125	
126	    http = ctx->data;
127	
128	    if (ctx->state) {
129	        ngx_js_http_error(http, "\"%V\" could not be resolved (%i: %s)",
130	                          &ctx->name, ctx->state,
131	                          ngx_resolver_strerror(ctx->state));
132	        return;
133	    }
134	
135	    ngx_log_debug1(NGX_LOG_DEBUG_EVENT, http->log, 0,
136	                   "http resolved: \"%V\"", &ctx->name);
137	
138	#if (NGX_DEBUG)
139	    {
140	    u_char      text[NGX_SOCKADDR_STRLEN];
141	    ngx_str_t   addr;
142	    ngx_uint_t  i;
143	
144	    addr.data = text;
145	
146	    for (i = 0; i < ctx->naddrs; i++) {
147	        addr.len = ngx_sock_ntop(ctx->addrs[i].sockaddr, ctx->addrs[i].socklen,
148	                                 text, NGX_SOCKADDR_STRLEN, 0);
149	
150	        ngx_log_debug1(NGX_LOG_DEBUG_EVENT, http->log, 0,
151	                       "name was resolved to \"%V\"", &addr);
152	    }
153	    }
154	#endif
155	
156	    http->naddrs = ctx->naddrs;
157	    http->addrs = ngx_pcalloc(http->pool, http->naddrs * sizeof(ngx_addr_t));
158	
159	    if (http->addrs == NULL) {
160	        goto failed;
161	    }
162	
163	    for (i = 0; i < ctx->naddrs; i++) {
164	        socklen = ctx->addrs[i].socklen;
165	
166	        sockaddr = ngx_palloc(http->pool, socklen);
167	        if (sockaddr == NULL) {
168	            goto failed;
169	        }
170	
171	        ngx_memcpy(sockaddr, ctx->addrs[i].sockaddr, socklen);
172	        ngx_inet_set_port(sockaddr, http->connect_port);
173	
174	        http->addrs[i].sockaddr = sockaddr;
175	        http->addrs[i].socklen = socklen;
176	
177	        p = ngx_pnalloc(http->pool, NGX_SOCKADDR_STRLEN);
178	        if (p == NULL) {
179	            goto failed;
180	        }
181	
182	        len = ngx_sock_ntop(sockaddr, socklen, p, NGX_SOCKADDR_STRLEN, 1);
183	        http->addrs[i].name.len = len;
184	        http->addrs[i].name.data = p;
185	    }
186	
187	    ngx_js_http_resolve_done(http);
188	
189	    ngx_js_http_connect(http);
190	
191	    return;
192	
193	failed:
194	
195	    ngx_js_http_error(http, "memory error");
196	}
