257	void
258	ngx_js_http_connect(ngx_js_http_t *http)
259	{
260	    ngx_int_t          rc;
261	    ngx_addr_t        *addr;
262	    ngx_connection_t  *c;
263	
264	    addr = &http->addrs[http->naddr];
265	
266	    ngx_log_debug2(NGX_LOG_DEBUG_EVENT, http->log, 0,
267	                   "js http connect %ui/%ui", http->naddr, http->naddrs);
268	
269	    http->peer.sockaddr = addr->sockaddr;
270	    http->peer.socklen = addr->socklen;
271	    http->peer.name = &addr->name;
272	    http->peer.get = ngx_event_get_peer;
273	    http->peer.log = http->log;
274	    http->peer.log_error = NGX_ERROR_ERR;
275	
276	    rc = ngx_js_http_get_keepalive_connection(http);
277	    if (rc != NGX_OK) {
278	        rc = ngx_event_connect_peer(&http->peer);
279	        if (rc == NGX_ERROR) {
280	            ngx_js_http_error(http, "connect failed");
281	            return;
282	        }
283	
284	        if (rc == NGX_BUSY || rc == NGX_DECLINED) {
285	            ngx_js_http_next(http);
286	            return;
287	        }
288	    }
289	
290	    c = http->peer.connection;
291	
292	    c->requests++;
293	    c->data = http;
294	
295	    if (c->pool == NULL) {
296	        /* we need separate pool here to be able to cache SSL connections */
297	        c->pool = ngx_create_pool(128, http->log);
298	        if (c->pool == NULL) {
299	            ngx_js_http_error(http, "create pool failed");
300	            return;
301	        }
302	    }
303	
304	    c->write->handler = ngx_js_http_write_handler;
305	    c->read->handler = ngx_js_http_read_handler;
306	
307	    ngx_add_timer(c->read, http->conf->timeout);
308	    ngx_add_timer(c->write, http->conf->timeout);
309	
310	#if (NGX_SSL)
311	    if (ngx_js_conf_proxy(http->conf) && http->ssl != NULL && c->ssl == NULL) {
312	        http->proxy.pending = ngx_js_chain_to_buf(http->pool, &http->chain);
313	        if (http->proxy.pending == NULL) {
314	            ngx_js_http_error(http, "memory error");
315	            return;
316	        }
317	
318	        njs_chb_destroy(&http->chain);
319	        ngx_js_http_build_connect_request(http);
320	
321	        http->proxy.state = HTTP_STATE_PROXY_CONNECT_PENDING;
322	        http->process = ngx_js_http_process_connect_response;
323	
324	    } else {
325	        if (ngx_js_conf_proxy(http->conf) && http->ssl != NULL && c->ssl != NULL) {
326	            http->proxy.state = HTTP_STATE_PROXY_TUNNEL_READY;
327	        }
328	
329	        http->process = ngx_js_http_process_status_line;
330	    }
331	
332	    if (http->ssl != NULL && c->ssl == NULL && !ngx_js_conf_proxy(http->conf)) {
333	        ngx_js_http_ssl_init_connection(http);
334	        return;
335	    }
336	#else
337	    http->process = ngx_js_http_process_status_line;
338	#endif
339	
340	    if (rc == NGX_OK) {
341	        ngx_js_http_write_handler(c->write);
342	    }
343	}
344	
345	
346	#if (NGX_SSL)
347	
348	static void
349	ngx_js_http_ssl_init_connection(ngx_js_http_t *http)
350	{
351	    ngx_int_t          rc;
352	    ngx_connection_t  *c;
353	
354	    c = http->peer.connection;
355	
356	    ngx_log_debug2(NGX_LOG_DEBUG_EVENT, http->log, 0,
357	                   "js http secure connect %ui/%ui", http->naddr,
358	                   http->naddrs);
359	
360	    if (ngx_ssl_create_connection(http->ssl, c, NGX_SSL_BUFFER|NGX_SSL_CLIENT)
361	        != NGX_OK)
362	    {
363	        ngx_js_http_error(http, "failed to create ssl connection");
364	        return;
365	    }
366	
367	    c->sendfile = 0;
368	
369	    if (ngx_js_http_ssl_name(http) != NGX_OK) {
370	        ngx_js_http_error(http, "failed to create ssl connection");
371	        return;
372	    }
373	
374	    c->log->action = "SSL handshaking to http target";
375	
376	    rc = ngx_ssl_handshake(c);
377	
378	    if (rc == NGX_AGAIN) {
379	        c->data = http;
380	        c->ssl->handler = ngx_js_http_ssl_handshake_handler;
381	        return;
382	    }
383	
384	    ngx_js_http_ssl_handshake(http);
385	}
