389	ngx_js_http_ssl_handshake_handler(ngx_connection_t *c)
390	{
391	    ngx_js_http_t  *http;
392	
393	    http = c->data;
394	
395	    http->peer.connection->write->handler = ngx_js_http_write_handler;
396	    http->peer.connection->read->handler = ngx_js_http_read_handler;
397	
