402	static void
403	ngx_js_http_ssl_handshake(ngx_js_http_t *http)
404	{
405	    long               rc;
406	    ngx_connection_t  *c;
407	
408	    c = http->peer.connection;
409	
410	    if (c->ssl->handshaked) {
411	        if (http->ssl_verify) {
412	            rc = SSL_get_verify_result(c->ssl->connection);
413	
414	            if (rc != X509_V_OK) {
415	                ngx_log_error(NGX_LOG_ERR, c->log, 0,
416	                              "js http SSL certificate verify error: (%l:%s)",
417	                              rc, X509_verify_cert_error_string(rc));
418	                goto failed;
419	            }
420	
421	            if (ngx_ssl_check_host(c, &http->host) != NGX_OK) {
422	                ngx_log_error(NGX_LOG_ERR, c->log, 0,
423	                              "js http SSL certificate does not match \"%V\"",
424	                              &http->host);
425	                goto failed;
426	            }
427	        }
428	
429	        c->write->handler = ngx_js_http_write_handler;
430	        c->read->handler = ngx_js_http_read_handler;
431	
432	        if (c->read->ready) {
433	            ngx_post_event(c->read, &ngx_posted_events);
434	        }
435	
436	        if (http->proxy.state == HTTP_STATE_PROXY_TUNNEL_READY) {
437	            ngx_log_debug0(NGX_LOG_DEBUG_EVENT, http->log, 0,
438	                           "js http send origin request");
439	
440	            http->buffer = http->proxy.pending;
441	            http->proxy.pending = NULL;
442	            http->proxy.state = HTTP_STATE_ORIGIN_REQUEST_SENT;
443	        }
444	
445	        http->process = ngx_js_http_process_status_line;
446	        ngx_js_http_write_handler(c->write);
447	
448	        return;
449	    }
450	
451	failed:
452	
453	    ngx_js_http_next(http);
454	}
