457	static ngx_int_t
458	ngx_js_http_ssl_name(ngx_js_http_t *http)
459	{
460	#ifdef SSL_CTRL_SET_TLSEXT_HOSTNAME
461	    u_char  *p;
462	
463	    /* as per RFC 6066, literal IPv4 and IPv6 addresses are not permitted */
464	    ngx_str_t  *name = &http->host;
465	
466	    if (name->len == 0 || *name->data == '[') {
467	        goto done;
468	    }
469	
470	    if (ngx_inet_addr(name->data, name->len) != INADDR_NONE) {
471	        goto done;
472	    }
473	
474	    /*
475	     * SSL_set_tlsext_host_name() needs a null-terminated string,
476	     * hence we explicitly null-terminate name here
477	     */
478	
479	    p = ngx_pnalloc(http->pool, name->len + 1);
480	    if (p == NULL) {
481	        return NGX_ERROR;
482	    }
483	
484	    (void) ngx_cpystrn(p, name->data, name->len + 1);
485	
486	    name->data = p;
487	
488	    ngx_log_debug1(NGX_LOG_DEBUG_EVENT, http->log, 0,
489	                   "js http SSL server name: \"%s\"", name->data);
490	
491	    if (SSL_set_tlsext_host_name(http->peer.connection->ssl->connection,
492	                                 (char *) name->data)
493	        == 0)
494	    {
495	        ngx_ssl_error(NGX_LOG_ERR, http->log, 0,
496	                      "SSL_set_tlsext_host_name(\"%s\") failed", name->data);
497	        return NGX_ERROR;
498	    }
499	
500	#endif
501	done:
502	
503	    return NGX_OK;
504	}
