507	static void
508	ngx_js_http_build_connect_request(ngx_js_http_t *http)
509	{
510	    NGX_CHB_CTX_INIT(&http->chain, http->pool);
511	
512	    njs_chb_append_literal(&http->chain, "CONNECT ");
513	
514	    njs_chb_append(&http->chain, http->host.data, http->host.len);
515	    njs_chb_sprintf(&http->chain, 32, ":%d HTTP/1.1" CRLF, http->port);
516	
517	    njs_chb_append_literal(&http->chain, "Host: ");
518	
519	    njs_chb_append(&http->chain, http->host.data, http->host.len);
520	    njs_chb_sprintf(&http->chain, 32, ":%d" CRLF, http->port);
521	
522	    if (http->proxy.auth.len != 0) {
523	        njs_chb_append(&http->chain, http->proxy.auth.data,
524	                       http->proxy.auth.len);
525	    }
526	
527	    njs_chb_append_literal(&http->chain, CRLF);
528	}
