531	static ngx_int_t
532	ngx_js_http_process_connect_response(ngx_js_http_t *http)
533	{
534	    ngx_int_t             rc;
535	    ngx_buf_t            *b;
536	    ngx_js_http_parse_t  *hp;
537	
538	    b = http->buffer;
539	    hp = &http->http_parse;
540	
541	    ngx_log_debug0(NGX_LOG_DEBUG_EVENT, http->log, 0,
542	                   "js http process CONNECT response");
543	
544	    rc = ngx_js_http_parse_status_line(hp, b);
545	
546	    if (rc == NGX_AGAIN) {
547	        return NGX_AGAIN;
548	    }
549	
550	    if (rc != NGX_OK) {
551	        ngx_js_http_error(http, "proxy CONNECT: invalid status line");
552	        return NGX_ERROR;
553	    }
554	
555	    if (hp->code != 200) {
556	        ngx_js_http_error(http, "proxy CONNECT failed with status %ui",
557	                         hp->code);
558	        return NGX_ERROR;
559	    }
560	
561	    ngx_log_debug1(NGX_LOG_DEBUG_EVENT, http->log, 0,
562	                   "js http proxy CONNECT status: %ui", hp->code);
563	
564	    for (;;) {
565	        rc = ngx_js_http_parse_header_line(hp, b);
566	
567	        if (rc == NGX_OK) {
568	            ngx_log_debug2(NGX_LOG_DEBUG_EVENT, http->log, 0,
569	                          "js http CONNECT header: \"%*s\"",
570	                          hp->header_end - hp->header_name_start,
571	                          hp->header_name_start);
572	            continue;
573	        }
574	
575	        if (rc == NGX_DONE) {
576	            ngx_log_debug0(NGX_LOG_DEBUG_EVENT, http->log, 0,
577	                          "js http proxy tunnel established");
578	            break;
579	        }
580	
581	        if (rc == NGX_AGAIN) {
582	            return NGX_AGAIN;
583	        }
584	
585	        ngx_js_http_error(http, "proxy CONNECT: invalid headers");
586	        return NGX_ERROR;
587	    }
588	
589	    http->proxy.state = HTTP_STATE_PROXY_TUNNEL_READY;
590	
591	    ngx_memzero(hp, sizeof(*hp));
592	
593	    if (http->ssl == NULL) {
594	        ngx_js_http_error(http, "proxy CONNECT: SSL not configured");
595	        return NGX_ERROR;
596	    }
597	
598	    ngx_log_debug0(NGX_LOG_DEBUG_EVENT, http->log, 0,
599	                   "js http init SSL through proxy tunnel");
600	
601	    ngx_js_http_ssl_init_connection(http);
602	    return NGX_OK;
603	}
604	
605	#endif
