608	static void
609	ngx_js_http_next(ngx_js_http_t *http)
610	{
611	    ngx_log_debug0(NGX_LOG_DEBUG_EVENT, http->log, 0, "js http next addr");
612	
613	    if (++http->naddr >= http->naddrs) {
614	        ngx_js_http_error(http, "connect failed");
615	        return;
616	    }
617	
618	    if (http->peer.connection != NULL) {
619	        ngx_js_http_close_connection(http->peer.connection);
620	        http->peer.connection = NULL;
621	    }
622	
623	    http->buffer = NULL;
624	
625	    ngx_js_http_connect(http);
626	}
