628	
629	static void
630	ngx_js_http_write_handler(ngx_event_t *wev)
631	{
632	    ssize_t            n, size;
633	    ngx_buf_t         *b;
634	    ngx_js_http_t     *http;
635	    ngx_connection_t  *c;
636	
637	    c = wev->data;
638	    http = c->data;
639	
640	    ngx_log_debug0(NGX_LOG_DEBUG_EVENT, wev->log, 0, "js http write handler");
641	
642	    if (wev->timedout) {
643	        ngx_js_http_error(http, "write timed out");
644	        return;
645	    }
646	
647	#if (NGX_SSL)
648	    if (http->ssl != NULL && http->peer.connection->ssl == NULL
649	        && !ngx_js_conf_proxy(http->conf))
650	    {
651	        ngx_js_http_ssl_init_connection(http);
652	        return;
653	    }
654	#endif
655	
656	    b = http->buffer;
657	
658	    if (b == NULL) {
659	        b = ngx_js_chain_to_buf(http->pool, &http->chain);
660	        if (b == NULL) {
661	            ngx_js_http_error(http, "memory error");
662	            return;
663	        }
664	
665	        http->buffer = b;
666	    }
667	
668	    size = b->last - b->pos;
669	
670	    n = c->send(c, b->pos, size);
671	
672	    if (n == NGX_ERROR) {
673	        ngx_js_http_next(http);
674	        return;
675	    }
676	
677	    if (n > 0) {
678	        b->pos += n;
679	
680	        if (n == size) {
681	            wev->handler = ngx_js_http_dummy_handler;
682	
683	            http->buffer = NULL;
684	
685	            if (wev->timer_set) {
686	                ngx_del_timer(wev);
687	            }
688	
689	            if (ngx_handle_write_event(wev, 0) != NGX_OK) {
690	                ngx_js_http_error(http, "write failed");
691	            }
692	
693	            return;
694	        }
695	    }
696	
697	    if (!wev->timer_set) {
698	        ngx_add_timer(wev, http->conf->timeout);
699	    }
700	}
