702	
703	static void
704	ngx_js_http_read_handler(ngx_event_t *rev)
705	{
706	    ssize_t            n, size;
707	    ngx_int_t          rc;
708	    ngx_buf_t         *b;
709	    ngx_js_http_t     *http;
710	    ngx_connection_t  *c;
711	
712	    c = rev->data;
713	    http = c->data;
714	
715	    ngx_log_debug0(NGX_LOG_DEBUG_EVENT, rev->log, 0, "js http read handler");
716	
717	    if (rev->timedout) {
718	        ngx_js_http_error(http, "read timed out");
719	        return;
720	    }
721	
722	    if (http->buffer == NULL) {
723	        b = ngx_create_temp_buf(http->pool, http->buffer_size);
724	        if (b == NULL) {
725	            ngx_js_http_error(http, "memory error");
726	            return;
727	        }
728	
729	        http->buffer = b;
730	    }
731	
732	    for ( ;; ) {
733	        b = http->buffer;
734	        size = b->end - b->last;
735	
736	        n = c->recv(c, b->last, size);
737	
738	        if (n > 0) {
739	            b->last += n;
740	
741	            rc = http->process(http);
742	
743	            if (rc == NGX_ERROR) {
744	                return;
745	            }
746	
747	            if (rc == NGX_DONE) {
748	                break;
749	            }
750	
751	            continue;
752	        }
753	
754	        if (n == NGX_AGAIN) {
755	            if (ngx_handle_read_event(rev, 0) != NGX_OK) {
756	                ngx_js_http_error(http, "read failed");
757	            }
758	
759	            return;
760	        }
761	
762	        if (n == NGX_ERROR) {
763	            ngx_js_http_next(http);
764	            return;
765	        }
766	
767	        break;
768	    }
769	
770	    http->done = 1;
771	
772	    rc = http->process(http);
773	
774	    if (rc == NGX_DONE) {
775	        /* handler was called */
776	        return;
777	    }
778	
779	    if (rc == NGX_AGAIN) {
780	        ngx_js_http_error(http, "prematurely closed connection");
781	    }
782	}
