793	ngx_js_http_process_status_line(ngx_js_http_t *http)
794	{
795	    ngx_int_t             rc;
796	    ngx_js_http_parse_t  *hp;
797	
798	    hp = &http->http_parse;
799	
800	    rc = ngx_js_http_parse_status_line(hp, http->buffer);
801	
802	    if (rc == NGX_OK) {
803	        ngx_log_debug1(NGX_LOG_DEBUG_EVENT, http->log, 0, "js http status %ui",
804	                       hp->code);
805	
806	        http->response.code = hp->code;
807	        http->response.status_text.data = hp->status_text;
808	        http->response.status_text.len = hp->status_text_end - hp->status_text;
809	        http->process = ngx_js_http_process_headers;
