813	        }
814	
815	        return http->process(http);
816	    }
817	
818	    if (rc == NGX_AGAIN) {
819	        return NGX_AGAIN;
820	    }
821	
822	    /* rc == NGX_ERROR */
823	
824	    ngx_js_http_error(http, "invalid http status line");
