830	static ngx_int_t
831	ngx_js_http_process_headers(ngx_js_http_t *http)
832	{
833	    size_t                len, vlen;
834	    ngx_int_t             rc;
835	    ngx_js_http_parse_t  *hp;
836	
837	    ngx_log_debug0(NGX_LOG_DEBUG_EVENT, http->log, 0,
838	                   "js http process headers");
839	
840	    hp = &http->http_parse;
841	
842	    if (http->response.headers.header_list.size == 0) {
843	        rc = ngx_list_init(&http->response.headers.header_list, http->pool, 4,
844	                           sizeof(ngx_js_tb_elt_t));
845	        if (rc != NGX_OK) {
846	            ngx_js_http_error(http, "alloc failed");
847	            return NGX_ERROR;
848	        }
849	    }
850	
851	    for ( ;; ) {
852	        rc = ngx_js_http_parse_header_line(hp, http->buffer);
853	
854	        if (rc == NGX_OK) {
855	            len = hp->header_name_end - hp->header_name_start;
856	            vlen = hp->header_end - hp->header_start;
857	
858	            rc = http->append_headers(http, &http->response.headers,
859	                                       hp->header_name_start, len,
860	                                       hp->header_start, vlen);
861	
862	            if (rc == NGX_ERROR) {
863	                ngx_js_http_error(http, "cannot add respose header");
864	                return NGX_ERROR;
865	            }
866	
867	            ngx_log_debug4(NGX_LOG_DEBUG_EVENT, http->log, 0,
868	                           "js http header \"%*s: %*s\"",
869	                           len, hp->header_name_start, vlen, hp->header_start);
870	
871	            if (len == (sizeof("Transfer-Encoding") -1)
872	                && vlen == (sizeof("chunked") - 1)
873	                && ngx_strncasecmp(hp->header_name_start,
874	                                   (u_char *) "Transfer-Encoding", len) == 0
875	                && ngx_strncasecmp(hp->header_start, (u_char *) "chunked",
876	                                   vlen) == 0)
877	            {
878	                http->chunked = 1;
879	            }
880	
881	            if (len == (sizeof("Connection") - 1)
882	                && ngx_strncasecmp(hp->header_name_start,
883	                                   (u_char *) "Connection", len) == 0)
884	            {
885	                if (vlen == (sizeof("close") - 1)
886	                    && ngx_strncasecmp(hp->header_start, (u_char *) "close",
887	                                       vlen) == 0)
888	                {
889	                    http->keepalive = 0;
890	                }
891	            }
892	
893	            if (len == (sizeof("Content-Length") - 1)
894	                && ngx_strncasecmp(hp->header_name_start,
895	                                   (u_char *) "Content-Length", len) == 0)
896	            {
897	                http->content_length_n = ngx_atoof(hp->header_start, vlen);
898	                if (http->content_length_n == NGX_ERROR) {
899	                    ngx_js_http_error(http, "invalid http content length");
900	                    return NGX_ERROR;
901	                }
902	
903	                if (!http->header_only
904	                    && http->content_length_n
905	                       > (off_t) http->max_response_body_size)
906	                {
907	                    ngx_js_http_error(http,
908	                                      "http content length is too large");
909	                    return NGX_ERROR;
910	                }
911	            }
912	
913	            continue;
914	        }
915	
916	        if (rc == NGX_DONE) {
917	            http->response.headers.guard = GUARD_IMMUTABLE;
918	            break;
919	        }
920	
921	        if (rc == NGX_AGAIN) {
922	            return NGX_AGAIN;
923	        }
924	
925	        /* rc == NGX_ERROR */
926	
927	        ngx_js_http_error(http, "invalid http header");
928	
929	        return NGX_ERROR;
930	    }
931	
932	    njs_chb_destroy(&http->chain);
933	
934	    http->process = ngx_js_http_process_body;
935	
936	    return http->process(http);
937	}
938	
939	
940	static ngx_int_t
941	ngx_js_http_process_body(ngx_js_http_t *http)
942	{
943	    ssize_t     size, chsize, need;
944	    ngx_int_t   rc;
945	    ngx_buf_t  *b;
946	
947	    ngx_log_debug1(NGX_LOG_DEBUG_EVENT, http->log, 0,
948	                   "js http process body done:%ui", (ngx_uint_t) http->done);
949	
950	    if (http->done) {
951	        size = njs_chb_size(&http->response.chain);
952	        if (size < 0) {
953	            ngx_js_http_error(http, "memory error");
954	            return NGX_ERROR;
955	        }
956	
957	        if (!http->header_only
958	            && http->chunked
959	            && http->content_length_n == -1)
960	        {
961	            ngx_js_http_error(http, "invalid http chunked response");
962	            return NGX_ERROR;
963	        }
964	
965	        if (http->header_only
966	            || http->content_length_n == -1
967	            || size == http->content_length_n)
968	        {
969	            http->ready_handler(http);
970	            return NGX_DONE;
971	        }
972	
973	        if (size < http->content_length_n) {
974	            return NGX_AGAIN;
975	        }
976	
977	        ngx_js_http_error(http, "http trailing data");
978	        return NGX_ERROR;
979	    }
980	
981	    b = http->buffer;
982	
983	    if (http->chunked) {
984	        rc = ngx_js_http_parse_chunked(&http->http_chunk_parse, b,
985	                                       &http->response.chain);
986	        if (rc == NGX_ERROR) {
987	            ngx_js_http_error(http, "invalid http chunked response");
988	            return NGX_ERROR;
989	        }
990	
991	        size = njs_chb_size(&http->response.chain);
992	
993	        if (rc == NGX_OK) {
994	            http->content_length_n = size;
995	        }
996	
997	        if (size > http->max_response_body_size * 10) {
998	            ngx_js_http_error(http, "very large http chunked response");
999	            return NGX_ERROR;
1000	        }
1001	
1002	        b->pos = http->http_chunk_parse.pos;
1003	
1004	    } else {
1005	        size = njs_chb_size(&http->response.chain);
1006	
1007	        if (http->header_only) {
1008	            need = 0;
1009	
1010	        } else  if (http->content_length_n == -1) {
1011	            need = http->max_response_body_size - size;
1012	
1013	        } else {
1014	            need = http->content_length_n - size;
1015	        }
1016	
1017	        chsize = ngx_min(need, b->last - b->pos);
1018	
1019	        if (size + chsize > http->max_response_body_size) {
1020	            ngx_js_http_error(http, "http response body is too large");
1021	            return NGX_ERROR;
1022	        }
1023	
1024	        if (chsize > 0) {
1025	            njs_chb_append(&http->response.chain, b->pos, chsize);
1026	            b->pos += chsize;
1027	        }
1028	
1029	        rc = (need > chsize) ? NGX_AGAIN : NGX_DONE;
1030	    }
1031	
1032	    if (b->pos == b->end) {
1033	        if (http->chunk == NULL) {
1034	            b = ngx_create_temp_buf(http->pool, http->buffer_size);
1035	            if (b == NULL) {
1036	                ngx_js_http_error(http, "memory error");
1037	                return NGX_ERROR;
1038	            }
1039	
1040	            http->buffer = b;
1041	            http->chunk = b;
1042	
1043	        } else {
1044	            b->last = b->start;
1045	            b->pos = b->start;
1046	        }
1047	    }
1048	
1049	    return rc;
1050	}
