1053	static ngx_int_t
1054	ngx_js_http_parse_status_line(ngx_js_http_parse_t *hp, ngx_buf_t *b)
1055	{
1056	    u_char   ch;
1057	    u_char  *p;
1058	    enum {
1059	        sw_start = 0,
1060	        sw_H,
1061	        sw_HT,
1062	        sw_HTT,
1063	        sw_HTTP,
1064	        sw_first_major_digit,
1065	        sw_major_digit,
1066	        sw_first_minor_digit,
1067	        sw_minor_digit,
1068	        sw_status,
1069	        sw_space_after_status,
1070	        sw_status_text,
1071	        sw_almost_done
1072	    } state;
1073	
1074	    state = hp->state;
1075	
1076	    for (p = b->pos; p < b->last; p++) {
1077	        ch = *p;
1078	
1079	        switch (state) {
1080	
1081	        /* "HTTP/" */
1082	        case sw_start:
1083	            switch (ch) {
1084	            case 'H':
1085	                state = sw_H;
1086	                break;
1087	            default:
1088	                return NGX_ERROR;
1089	            }
1090	            break;
1091	
1092	        case sw_H:
1093	            switch (ch) {
1094	            case 'T':
1095	                state = sw_HT;
1096	                break;
1097	            default:
1098	                return NGX_ERROR;
1099	            }
1100	            break;
1101	
1102	        case sw_HT:
1103	            switch (ch) {
1104	            case 'T':
1105	                state = sw_HTT;
1106	                break;
1107	            default:
1108	                return NGX_ERROR;
1109	            }
1110	            break;
1111	
1112	        case sw_HTT:
1113	            switch (ch) {
1114	            case 'P':
1115	                state = sw_HTTP;
1116	                break;
1117	            default:
1118	                return NGX_ERROR;
1119	            }
1120	            break;
1121	
1122	        case sw_HTTP:
1123	            switch (ch) {
1124	            case '/':
1125	                state = sw_first_major_digit;
1126	                break;
1127	            default:
1128	                return NGX_ERROR;
1129	            }
1130	            break;
1131	
1132	        /* the first digit of major HTTP version */
1133	        case sw_first_major_digit:
1134	            if (ch < '1' || ch > '9') {
1135	                return NGX_ERROR;
1136	            }
1137	
1138	            hp->http_major = ch - '0';
1139	
1140	            if (hp->http_major > 1) {
1141	                return NGX_ERROR;
1142	            }
1143	
1144	            state = sw_major_digit;
1145	            break;
1146	
1147	        /* the major HTTP version or dot */
1148	        case sw_major_digit:
1149	            if (ch == '.') {
1150	                state = sw_first_minor_digit;
1151	                break;
1152	            }
1153	
1154	            if (ch < '0' || ch > '9') {
1155	                return NGX_ERROR;
1156	            }
1157	
1158	            hp->http_major = hp->http_major * 10 + (ch - '0');
1159	
1160	            if (hp->http_major > 1) {
1161	                return NGX_ERROR;
1162	            }
1163	
1164	            break;
1165	
1166	        /* the first digit of minor HTTP version */
1167	        case sw_first_minor_digit:
1168	            if (ch < '0' || ch > '9') {
1169	                return NGX_ERROR;
1170	            }
1171	
1172	            hp->http_minor = ch - '0';
1173	            state = sw_minor_digit;
1174	            break;
1175	
1176	        /* the minor HTTP version or the end of the request line */
1177	        case sw_minor_digit:
1178	            if (ch == ' ') {
1179	                state = sw_status;
1180	                break;
1181	            }
1182	
1183	            if (ch < '0' || ch > '9') {
1184	                return NGX_ERROR;
1185	            }
1186	
1187	            if (hp->http_minor > 99) {
1188	                return NGX_ERROR;
1189	            }
1190	
1191	            hp->http_minor = hp->http_minor * 10 + (ch - '0');
1192	
1193	            break;
1194	
1195	        /* HTTP status code */
1196	        case sw_status:
1197	            if (ch == ' ') {
1198	                break;
1199	            }
1200	
1201	            if (ch < '0' || ch > '9') {
1202	                return NGX_ERROR;
1203	            }
1204	
1205	            hp->code = hp->code * 10 + (ch - '0');
1206	
1207	            if (++hp->count == 3) {
1208	                state = sw_space_after_status;
1209	            }
1210	
1211	            break;
1212	
1213	        /* space or end of line */
1214	        case sw_space_after_status:
1215	            switch (ch) {
1216	            case ' ':
1217	                state = sw_status_text;
1218	                break;
1219	            case '.':                    /* IIS may send 403.1, 403.2, etc */
1220	                state = sw_status_text;
1221	                break;
1222	            case CR:
1223	                break;
1224	            case LF:
1225	                goto done;
1226	            default:
1227	                return NGX_ERROR;
1228	            }
1229	            break;
1230	
1231	        /* any text until end of line */
1232	        case sw_status_text:
1233	            switch (ch) {
1234	            case CR:
1235	                hp->status_text_end = p;
1236	                state = sw_almost_done;
1237	                break;
1238	            case LF:
1239	                hp->status_text_end = p;
1240	                goto done;
1241	            }
1242	
1243	            if (hp->status_text == NULL) {
1244	                hp->status_text = p;
1245	            }
1246	
1247	            break;
1248	
1249	        /* end of status line */
1250	        case sw_almost_done:
1251	            switch (ch) {
1252	            case LF:
1253	                goto done;
1254	            default:
1255	                return NGX_ERROR;
1256	            }
1257	        }
1258	    }
1259	
1260	    b->pos = p;
1261	    hp->state = state;
1262	
1263	    return NGX_AGAIN;
1264	
1265	done:
1266	
1267	    b->pos = p + 1;
1268	    hp->state = sw_start;
1269	
1270	    hp->http_version = ngx_js_http_version(hp->http_major, hp->http_minor);
1271	
1272	    return NGX_OK;
1273	}
