1275	
1276	static ngx_int_t
1277	ngx_js_http_parse_header_line(ngx_js_http_parse_t *hp, ngx_buf_t *b)
1278	{
1279	    u_char  c, ch, *p;
1280	    enum {
1281	        sw_start = 0,
1282	        sw_name,
1283	        sw_space_before_value,
1284	        sw_value,
1285	        sw_space_after_value,
1286	        sw_almost_done,
1287	        sw_header_almost_done
1288	    } state;
1289	
1290	    state = hp->state;
1291	
1292	    for (p = b->pos; p < b->last; p++) {
1293	        ch = *p;
1294	
1295	        switch (state) {
1296	
1297	        /* first char */
1298	        case sw_start:
1299	
1300	            switch (ch) {
1301	            case CR:
1302	                hp->header_end = p;
1303	                state = sw_header_almost_done;
1304	                break;
1305	            case LF:
1306	                hp->header_end = p;
1307	                goto header_done;
1308	            default:
1309	                state = sw_name;
1310	                hp->header_name_start = p;
1311	
1312	                c = (u_char) (ch | 0x20);
1313	                if (c >= 'a' && c <= 'z') {
1314	                    break;
1315	                }
1316	
1317	                if (ch >= '0' && ch <= '9') {
1318	                    break;
1319	                }
1320	
1321	                return NGX_ERROR;
1322	            }
1323	            break;
1324	
1325	        /* header name */
1326	        case sw_name:
1327	            c = (u_char) (ch | 0x20);
1328	            if (c >= 'a' && c <= 'z') {
1329	                break;
1330	            }
1331	
1332	            if (ch == ':') {
1333	                hp->header_name_end = p;
1334	                state = sw_space_before_value;
1335	                break;
1336	            }
1337	
1338	            if (ch == '-' || ch == '_') {
1339	                break;
1340	            }
1341	
1342	            if (ch >= '0' && ch <= '9') {
1343	                break;
1344	            }
1345	
1346	            if (ch == CR) {
1347	                hp->header_name_end = p;
1348	                hp->header_start = p;
1349	                hp->header_end = p;
1350	                state = sw_almost_done;
1351	                break;
1352	            }
1353	
1354	            if (ch == LF) {
1355	                hp->header_name_end = p;
1356	                hp->header_start = p;
1357	                hp->header_end = p;
1358	                goto done;
1359	            }
1360	
1361	            return NGX_ERROR;
1362	
1363	        /* space* before header value */
1364	        case sw_space_before_value:
1365	            switch (ch) {
1366	            case ' ':
1367	                break;
1368	            case CR:
1369	                hp->header_start = p;
1370	                hp->header_end = p;
1371	                state = sw_almost_done;
1372	                break;
1373	            case LF:
1374	                hp->header_start = p;
1375	                hp->header_end = p;
1376	                goto done;
1377	            default:
1378	                hp->header_start = p;
1379	                state = sw_value;
1380	                break;
1381	            }
1382	            break;
1383	
1384	        /* header value */
1385	        case sw_value:
1386	            switch (ch) {
1387	            case ' ':
1388	                hp->header_end = p;
1389	                state = sw_space_after_value;
1390	                break;
1391	            case CR:
1392	                hp->header_end = p;
1393	                state = sw_almost_done;
1394	                break;
1395	            case LF:
1396	                hp->header_end = p;
1397	                goto done;
1398	            }
1399	            break;
1400	
1401	        /* space* before end of header line */
1402	        case sw_space_after_value:
1403	            switch (ch) {
1404	            case ' ':
1405	                break;
1406	            case CR:
1407	                state = sw_almost_done;
1408	                break;
1409	            case LF:
1410	                goto done;
1411	            default:
1412	                state = sw_value;
1413	                break;
1414	            }
1415	            break;
1416	
1417	        /* end of header line */
1418	        case sw_almost_done:
1419	            switch (ch) {
1420	            case LF:
1421	                goto done;
1422	            default:
1423	                return NGX_ERROR;
1424	            }
1425	
1426	        /* end of header */
1427	        case sw_header_almost_done:
1428	            switch (ch) {
1429	            case LF:
1430	                goto header_done;
1431	            default:
1432	                return NGX_ERROR;
1433	            }
1434	        }
1435	    }
1436	
1437	    b->pos = p;
1438	    hp->state = state;
1439	
1440	    return NGX_AGAIN;
1441	
1442	done:
1443	
1444	    b->pos = p + 1;
1445	    hp->state = sw_start;
1446	
1447	    return NGX_OK;
1448	
1449	header_done:
1450	
1451	    b->pos = p + 1;
1452	    hp->state = sw_start;
1453	
1454	    return NGX_DONE;
1455	}
