1458	#define                                                                       \
1459	ngx_size_is_sufficient(cs)                                                    \
1460	    (cs < ((__typeof__(cs)) 1 << (sizeof(cs) * 8 - 4)))
1461	
1462	
1463	#define NGX_JS_HTTP_CHUNK_MIDDLE     0
1464	#define NGX_JS_HTTP_CHUNK_ON_BORDER  1
1465	#define NGX_JS_HTTP_CHUNK_END        2
1466	
1467	
1468	static ngx_int_t
1469	ngx_js_http_chunk_buffer(ngx_js_http_chunk_parse_t *hcp, ngx_buf_t *b,
1470	    njs_chb_t *chain)
1471	{
1472	    size_t  size;
1473	
1474	    size = b->last - hcp->pos;
1475	
1476	    if (hcp->chunk_size < size) {
1477	        njs_chb_append(chain, hcp->pos, hcp->chunk_size);
1478	        hcp->pos += hcp->chunk_size;
1479	
1480	        return NGX_JS_HTTP_CHUNK_END;
1481	    }
1482	
1483	    njs_chb_append(chain, hcp->pos, size);
1484	    hcp->pos += size;
1485	
1486	    hcp->chunk_size -= size;
1487	
1488	    if (hcp->chunk_size == 0) {
1489	        return NGX_JS_HTTP_CHUNK_ON_BORDER;
1490	    }
1491	
1492	    return NGX_JS_HTTP_CHUNK_MIDDLE;
1493	}
1494	
1495	
1496	static ngx_int_t
1497	ngx_js_http_parse_chunked(ngx_js_http_chunk_parse_t *hcp,
1498	    ngx_buf_t *b, njs_chb_t *chain)
1499	{
1500	    u_char     c, ch;
1501	    ngx_int_t  rc;
1502	
1503	    enum {
1504	        sw_start = 0,
1505	        sw_chunk_size,
1506	        sw_chunk_size_linefeed,
1507	        sw_chunk_end_newline,
1508	        sw_chunk_end_linefeed,
1509	        sw_chunk,
1510	    } state;
1511	
1512	    state = hcp->state;
1513	
1514	    hcp->pos = b->pos;
1515	
1516	    while (hcp->pos < b->last) {
1517	        /*
1518	         * The sw_chunk state is tested outside the switch
1519	         * to preserve hcp->pos and to not touch memory.
1520	         */
1521	        if (state == sw_chunk) {
1522	            rc = ngx_js_http_chunk_buffer(hcp, b, chain);
1523	            if (rc == NGX_ERROR) {
1524	                return rc;
1525	            }
1526	
1527	            if (rc == NGX_JS_HTTP_CHUNK_MIDDLE) {
1528	                break;
1529	            }
1530	
1531	            state = sw_chunk_end_newline;
1532	
1533	            if (rc == NGX_JS_HTTP_CHUNK_ON_BORDER) {
1534	                break;
1535	            }
1536	
1537	            /* rc == NGX_JS_HTTP_CHUNK_END */
1538	        }
1539	
1540	        ch = *hcp->pos++;
1541	
1542	        switch (state) {
1543	
1544	        case sw_start:
1545	            state = sw_chunk_size;
1546	
1547	            c = ch - '0';
1548	
1549	            if (c <= 9) {
1550	                hcp->chunk_size = c;
1551	                continue;
1552	            }
1553	
1554	            c = (ch | 0x20) - 'a';
1555	
1556	            if (c <= 5) {
1557	                hcp->chunk_size = 0x0A + c;
1558	                continue;
1559	            }
1560	
1561	            return NGX_ERROR;
1562	
1563	        case sw_chunk_size:
1564	
1565	            c = ch - '0';
1566	
1567	            if (c > 9) {
1568	                c = (ch | 0x20) - 'a';
1569	
1570	                if (c <= 5) {
1571	                    c += 0x0A;
1572	
1573	                } else if (ch == '\r') {
1574	                    state = sw_chunk_size_linefeed;
1575	                    continue;
1576	
1577	                } else {
1578	                    return NGX_ERROR;
1579	                }
1580	            }
1581	
1582	            if (ngx_size_is_sufficient(hcp->chunk_size)) {
1583	                hcp->chunk_size = (hcp->chunk_size << 4) + c;
1584	                continue;
1585	            }
1586	
1587	            return NGX_ERROR;
1588	
1589	        case sw_chunk_size_linefeed:
1590	            if (ch == '\n') {
1591	
1592	                if (hcp->chunk_size != 0) {
1593	                    state = sw_chunk;
1594	                    continue;
1595	                }
1596	
1597	                hcp->last = 1;
1598	                state = sw_chunk_end_newline;
1599	                continue;
1600	            }
1601	
1602	            return NGX_ERROR;
1603	
1604	        case sw_chunk_end_newline:
1605	            if (ch == '\r') {
1606	                state = sw_chunk_end_linefeed;
1607	                continue;
1608	            }
1609	
1610	            return NGX_ERROR;
1611	
1612	        case sw_chunk_end_linefeed:
1613	            if (ch == '\n') {
1614	
1615	                if (!hcp->last) {
1616	                    state = sw_start;
1617	                    continue;
1618	                }
1619	
1620	                return NGX_OK;
1621	            }
1622	
1623	            return NGX_ERROR;
1624	
1625	        case sw_chunk:
1626	            /*
1627	             * This state is processed before the switch.
1628	             * It added here just to suppress a warning.
1629	             */
1630	            continue;
1631	        }
1632	    }
1633	
1634	    hcp->state = state;
1635	
1636	    return NGX_AGAIN;
1637	}
