1641	ngx_js_http_whitespace(u_char c)
1642	{
1643	    switch (c) {
1644	    case 0x09:  /* <TAB>  */
1645	    case 0x0A:  /* <LF>   */
1646	    case 0x0D:  /* <CR>   */
1647	    case 0x20:  /* <SP>   */
1648	        return 1;
1649	
1650	    default:
1651	        return 0;
1652	    }
1653	}
