1656	void
1657	ngx_js_http_trim(u_char **value, size_t *len, int trim_c0_control_or_space)
1658	{
1659	    u_char  *start, *end;
1660	
1661	    start = *value;
1662	    end = start + *len;
1663	
1664	    for ( ;; ) {
1665	        if (start == end) {
1666	            break;
1667	        }
1668	
1669	        if (ngx_js_http_whitespace(*start)
1670	            || (trim_c0_control_or_space && *start <= ' '))
1671	        {
1672	            start++;
1673	            continue;
1674	        }
1675	
1676	        break;
1677	    }
1678	
1679	    for ( ;; ) {
1680	        if (start == end) {
1681	            break;
1682	        }
1683	
1684	        end--;
1685	
1686	        if (ngx_js_http_whitespace(*end)
1687	            || (trim_c0_control_or_space && *end <= ' '))
1688	        {
1689	            continue;
1690	        }
1691	
1692	        end++;
1693	        break;
1694	    }
1695	
1696	    *value = start;
1697	    *len = end - start;
1698	}
