1701	void
1702	ngx_js_http_trim_ows(u_char **value, size_t *len)
1703	{
1704	    u_char  *start, *end;
1705	
1706	    start = *value;
1707	    end = start + *len;
1708	
1709	    while (start < end && (*start == ' ' || *start == '\t')) {
1710	        start++;
1711	    }
1712	
1713	    while (start < end) {
1714	        end--;
1715	
1716	        if (*end != ' ' && *end != '\t') {
1717	            end++;
1718	            break;
1719	        }
1720	    }
1721	
1722	    *value = start;
1723	    *len = end - start;
1724	}
