1727	static const uint32_t  token_map[] = {
1728	    0x00000000,  /* 0000 0000 0000 0000  0000 0000 0000 0000 */
1729	
1730	                 /* ?>=< ;:98 7654 3210  /.-, +*)( '&%$ #"!  */
1731	    0x03ff6cfa,  /* 0000 0011 1111 1111  0110 1100 1111 1010 */
1732	
1733	                 /* _^]\ [ZYX WVUT SRQP  ONML KJIH GFED CBA@ */
1734	    0xc7fffffe,  /* 1100 0111 1111 1111  1111 1111 1111 1110 */
1735	
1736	                 /*  ~}| {zyx wvut srqp  onml kjih gfed cba` */
1737	    0x57ffffff,  /* 0101 0111 1111 1111  1111 1111 1111 1111 */
1738	
1739	    0x00000000,  /* 0000 0000 0000 0000  0000 0000 0000 0000 */
1740	    0x00000000,  /* 0000 0000 0000 0000  0000 0000 0000 0000 */
1741	    0x00000000,  /* 0000 0000 0000 0000  0000 0000 0000 0000 */
1742	    0x00000000,  /* 0000 0000 0000 0000  0000 0000 0000 0000 */
1743	};
