1753	ngx_int_t
1754	ngx_js_check_header_name(u_char *name, size_t len)
1755	{
1756	    u_char  *p, *end;
1757	
1758	    p = name;
1759	    end = p + len;
1760	
1761	    while (p < end) {
1762	        if (!ngx_is_token(*p)) {
1763	            return NGX_ERROR;
1764	        }
1765	
1766	        p++;
1767	    }
1768	
1769	    return NGX_OK;
1770	}
