1793	ngx_int_t
1794	ngx_js_check_header_value(u_char *value, size_t len)
1795	{
1796	    u_char  *p, *end;
1797	
1798	    p = value;
1799	    end = p + len;
1800	
1801	    while (p < end) {
1802	        if (*p <= 0x08 || (*p >= 0x0a && *p <= 0x1f) || *p == 0x7f) {
1803	            return NGX_ERROR;
1804	        }
1805	
1806	        p++;
1807	    }
1808	
1809	    return NGX_OK;
