1817	    ngx_queue_t                    *q, *next;
1818	    ngx_connection_t               *c;
1819	    ngx_js_loc_conf_t              *conf;
1820	    ngx_js_http_keepalive_cache_t  *cache;
1821	
1822	    if (!http->keepalive) {
1823	        return NGX_DECLINED;
1824	    }
1825	
1826	    conf = http->conf;
1827	
1828	    host = &http->host;
1829	
1830	    for (q = ngx_queue_head(&conf->fetch_keepalive_cache);
1831	         q != ngx_queue_sentinel(&conf->fetch_keepalive_cache);
1832	         q = next)
1833	    {
1834	        next = ngx_queue_next(q);
1835	        cache = ngx_queue_data(q, ngx_js_http_keepalive_cache_t, queue);
1836	
1837	        if (host->len != cache->host_len) {
1838	            continue;
1839	        }
1840	
1841	#if (NGX_SSL)
1842	        if ((http->ssl != NULL) != (cache->ssl != 0)) {
1843	            continue;
1844	        }
1845	#endif
1846	
1847	        if (ngx_strncasecmp(host->data, cache->host, host->len) != 0) {
1848	            continue;
1849	        }
1850	
1851	        if (http->port != cache->port) {
1852	            continue;
1853	        }
1854	
1855	        c = cache->connection;
1856	
1857	        if (ngx_js_http_keepalive_check_connection(c) != NGX_OK) {
1858	            ngx_log_debug1(NGX_LOG_DEBUG_EVENT, http->log, 0,
1859	                           "js http keepalive closing cached connection: %d",
1860	                           c->fd);
1861	
1862	            ngx_queue_remove(q);
1863	            ngx_js_http_close_connection(c);
1864	            ngx_queue_insert_head(&conf->fetch_keepalive_free, q);
1865	
1866	            continue;
1867	        }
1868	
1869	        ngx_queue_remove(q);
1870	        ngx_queue_insert_head(&conf->fetch_keepalive_free, q);
1871	
1872	        goto found;
1873	    }
1874	
1875	    return NGX_DECLINED;
1876	
1877	found:
1878	
1879	    ngx_log_debug2(NGX_LOG_DEBUG_EVENT, http->log, 0,
1880	                   "js http keepalive using cached connection: %p:%d",
1881	                   c, c->fd);
1882	
1883	    c->idle = 0;
1884	    c->sent = 0;
1885	    c->data = NULL;
1886	    c->log = http->log;
1887	    c->pool->log = http->log;
1888	    c->read->log = http->log;
1889	    c->write->log = http->log;
1890	
1891	    if (c->read->timer_set) {
1892	        ngx_del_timer(c->read);
1893	    }
1894	
1895	    http->peer.cached = 1;
1896	    http->peer.connection = c;
1897	
1898	    return NGX_OK;
1899	}
