1909	        return NGX_DECLINED;
1910	    }
1911	
1912	    n = recv(c->fd, buf, 1, MSG_PEEK);
1913	
1914	    if (n == -1 && ngx_socket_errno == NGX_EAGAIN) {
1915	        c->read->ready = 0;
1916	
1917	        if (ngx_handle_read_event(c->read, 0) != NGX_OK) {
1918	            return NGX_ERROR;
1919	        }
1920	
1921	        return NGX_OK;
1922	    }
1923	
1924	    return NGX_DECLINED;
1925	}
