1928	static ngx_int_t
1929	ngx_js_http_free_keepalive_connection(ngx_js_http_t *http)
1930	{
1931	    ngx_uint_t                      i;
1932	    ngx_queue_t                    *q;
1933	    ngx_connection_t               *c;
1934	    ngx_js_loc_conf_t              *conf;
