1937	    ngx_log_debug0(NGX_LOG_DEBUG_EVENT, http->log, 0,
1938	                   "js http free keepalive connection");
1939	
1940	    c = http->peer.connection;
1941	
1942	    if (c == NULL
1943	        || c->read->eof
1944	        || c->read->error
1945	        || c->read->timedout
1946	        || c->write->error
1947	        || c->write->timedout)
1948	    {
1949	        return NGX_ERROR;
1950	    }
