1952	    if (c->requests >= http->conf->fetch_keepalive_requests) {
1953	        return NGX_DONE;
1954	    }
1955	
1956	    if (ngx_current_msec - c->start_time > http->conf->fetch_keepalive_time) {
1957	        return NGX_DONE;
1958	    }
1959	
1960	    if (ngx_terminate || ngx_exiting) {
1961	        return NGX_DONE;
1962	    }
1963	
1964	    if (ngx_handle_read_event(c->read, 0) != NGX_OK) {
1965	        return NGX_ERROR;
1966	    }
1967	
1968	    ngx_log_debug2(NGX_LOG_DEBUG_EVENT, http->log, 0,
1969	                   "js http free keepalive connection, "
1970	                   "saving connection: %p:%d", c, c->fd);
1971	
1972	    conf = http->conf;
1973	
1974	    if (ngx_queue_empty(&conf->fetch_keepalive_cache)
1975	        && ngx_queue_empty(&conf->fetch_keepalive_free))
1976	    {
1977	        cache = ngx_pcalloc(ngx_cycle->pool,
1978	                sizeof(ngx_js_http_keepalive_cache_t) * conf->fetch_keepalive);
1979	        if (cache == NULL) {
1980	            return NGX_ERROR;
1981	        }
1982	
1983	        for (i = 0; i < conf->fetch_keepalive; i++) {
1984	            ngx_queue_insert_head(&conf->fetch_keepalive_free,
1985	                                  &cache[i].queue);
1986	            cache[i].conf = conf;
1987	        }
1988	    }
1989	
1990	    if (ngx_queue_empty(&conf->fetch_keepalive_free)) {
1991	        /* evict from cache */
1992	        q = ngx_queue_last(&conf->fetch_keepalive_cache);
1993	        ngx_queue_remove(q);
1994	
1995	        cache = ngx_queue_data(q, ngx_js_http_keepalive_cache_t, queue);
1996	        ngx_log_debug1(NGX_LOG_DEBUG_EVENT, http->log, 0,
1997	                       "js http free keepalive connection, evicting: %d",
1998	                       cache->connection->fd);
1999	        ngx_js_http_close_connection(cache->connection);
2000	
2001	    } else {
2002	        q = ngx_queue_head(&conf->fetch_keepalive_free);
2003	        ngx_queue_remove(q);
2004	        cache = ngx_queue_data(q, ngx_js_http_keepalive_cache_t, queue);
2005	    }
2006	
2007	    ngx_queue_insert_head(&conf->fetch_keepalive_cache, q);
2008	
2009	    c = http->peer.connection;
2010	    http->peer.connection = NULL;
2011	
2012	    cache->connection = c;
2013	
2014	#if (NGX_SSL)
2015	    cache->ssl = (http->ssl != NULL);
2016	#endif
2017	    ngx_memcpy(cache->host, http->host.data, http->host.len);
2018	    cache->host_len = http->host.len;
2019	    cache->port = http->port;
2020	
2021	    c->read->delayed = 0;
2022	    ngx_add_timer(c->read, conf->fetch_keepalive_timeout);
2023	
2024	    if (c->write->timer_set) {
2025	        ngx_del_timer(c->write);
2026	    }
2027	
2028	    c->data = cache;
2029	    c->write->handler = ngx_js_http_keepalive_dummy_handler;
2030	    c->read->handler = ngx_js_http_keepalive_close_handler;
2031	
2032	    c->idle = 1;
2033	    c->log = ngx_cycle->log;
2034	    c->pool->log = ngx_cycle->log;
2035	    c->read->log = ngx_cycle->log;
2036	    c->write->log = ngx_cycle->log;
2037	
2038	    if (c->read->ready) {
2039	        ngx_js_http_keepalive_close_handler(c->read);
2040	    }
2041	
2042	    return NGX_OK;
2043	}
